			<details><summary>Edit connections and branding</summary><form method="POST" action="?/connections" class="connection-form" use:enhance={track(`connections:${tenant.id}`)}><input type="hidden" name="tenantId" value={tenant.id}/><input name="studioName" value={tenant.studioName} placeholder="Studio name" required/><input name="logoUrl" value={tenant.logoUrl} placeholder="HTTPS logo URL"/><input name="databaseUrl" type="password" placeholder="New Neon URL (blank keeps current)"/><input name="googleSheetId" value={tenant.googleSheetId} placeholder="Google Sheet ID"/><input name="ordersTab" value={tenant.ordersTab} placeholder="Orders tab"/><button disabled={pendingAction !== ''} aria-busy={pendingAction === `connections:${tenant.id}`}>{#if pendingAction === `connections:${tenant.id}`}<RefreshCw class="loading-icon" size={13}/>{/if}{pendingAction === `connections:${tenant.id}` ? 'Validating…' : 'Validate and update'}</button></form></details>
			{#if tenant.isDemo}<details class="danger"><summary>Reset demo data</summary><form method="POST" action="?/reset" class="inline-form" use:enhance={track(`reset:${tenant.id}`)}><input type="hidden" name="tenantId" value={tenant.id}/><input name="confirmation" placeholder="Type RESET" required/><button disabled={pendingAction !== ''} aria-busy={pendingAction === `reset:${tenant.id}`}>{#if pendingAction === `reset:${tenant.id}`}<RefreshCw class="loading-icon" size={13}/>{/if}{pendingAction === `reset:${tenant.id}` ? 'Resetting…' : 'Reset database and Sheet'}</button></form></details>{/if}
		</article>
		{/each}
		{#if !data.tenants.length}<div class="panel empty">No clients yet. Add the first isolated workspace.</div>{/if}
	</section>
	<section class="panel owner-security"><ShieldCheck size={20}/><div><h2>Owner security</h2><p>Changing your password signs out every owner session.</p></div><form method="POST" action="?/ownerPassword" use:enhance={track('owner-password')}><input name="password" type="password" minlength="10" placeholder="New owner password" required/><button disabled={pendingAction !== ''} aria-busy={pendingAction === 'owner-password'}>{#if pendingAction === 'owner-password'}<RefreshCw class="loading-icon" size={13}/>{/if}{pendingAction === 'owner-password' ? 'Changing…' : 'Change password'}</button></form></section>
</main>

