x;gap:7px}.empty{text-align:center;color:var(--muted);grid-column:1/-1}@media(max-width:850px){.tenant-grid{grid-template-columns:1fr}.grid{grid-template-columns:1fr}.grid .wide{grid-column:auto}.facts{grid-template-columns:1fr}.intro{align-items:flex-start;gap:18px}.owner-security{align-items:flex-start;flex-direction:column}.inline-form{grid-template-columns:1fr}.owner-head>div>span{display:none}}@media(max-width:560px){.intro{flex-direction:column}.checks,.actions{flex-direction:column}.owner-security form{width:100%;flex-direction:column}}
